/**
 * Notification model — core types for the notification system.
 *
 * Architecture: All notifications flow through the EventBus. Services emit
 * domain events (e.g., 'order:created'), the NotificationService listens
 * and dispatches to the appropriate NotificationAdapter(s) based on channel.
 *
 * Constraints:
 * - All adapters must implement the NotificationAdapter interface.
 * - All notifications must originate from EventBus event handlers.
 * - NotificationType must be extended when adding new notification categories.
 */

/** Supported notification delivery channels. */
export type NotificationChannel = 'email' | 'webhook' | 'in-app' | 'sms';

/** Categories of notifications the system can send. */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'user_welcome'
  | 'user_updated';

/** Priority levels for notification delivery. */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * The payload passed to notification adapters for delivery.
 * This is the channel-agnostic representation of a notification.
 */
export interface NotificationPayload {
  /** Unique notification ID. */
  id: string;
  /** The type/category of this notification. */
  type: NotificationType;
  /** Delivery channel for this notification. */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.). */
  recipient: string;
  /** Notification subject/title. */
  subject: string;
  /** Notification body content. */
  body: string;
  /** Priority level. */
  priority: NotificationPriority;
  /** Additional metadata (order ID, user ID, etc.). */
  metadata: Record<string, string>;
  /** When this notification was created. */
  createdAt: Date;
}

/**
 * A persisted notification record with delivery status tracking.
 */
export interface Notification extends NotificationPayload {
  /** Current delivery status. */
  status: NotificationStatus;
  /** When delivery was attempted. */
  sentAt: Date | null;
  /** Error message if delivery failed. */
  error: string | null;
}

/** Delivery status of a notification. */
export type NotificationStatus = 'pending' | 'sent' | 'failed';

/**
 * Input for creating a notification (before ID and timestamps are assigned).
 */
export interface CreateNotificationInput {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority?: NotificationPriority;
  metadata?: Record<string, string>;
}

/**
 * NotificationAdapter interface — contract for all notification delivery channels.
 *
 * Architecture constraint: Every notification channel (email, webhook, SMS, etc.)
 * MUST implement this interface. The NotificationService dispatches to adapters
 * based on the notification's channel field.
 *
 * Implementing a new channel:
 * 1. Add the channel name to NotificationChannel type in models/notification.ts
 * 2. Create a new adapter file in src/adapters/ implementing NotificationAdapter
 * 3. Register the adapter with NotificationService via registerAdapter()
 *
 * Adapters should:
 * - Be stateless where possible (no internal notification storage)
 * - Throw typed errors on failure (never return null/undefined for errors)
 * - Handle their own retries internally if needed
 */

import type { NotificationChannel, NotificationPayload } from '../models/notification.js';

/**
 * Result of a notification delivery attempt.
 */
export interface DeliveryResult {
  /** Whether delivery succeeded. */
  success: boolean;
  /** Error message if delivery failed. */
  error?: string;
  /** Channel-specific metadata (e.g., message ID from email provider). */
  providerMetadata?: Record<string, string>;
}

/**
 * Interface that all notification delivery adapters must implement.
 */
export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * @param payload - The notification to deliver.
   * @returns Result indicating success or failure with details.
   */
  send(payload: NotificationPayload): Promise<DeliveryResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails instead of sending them.
 * Replace the send() internals with a real email provider (SendGrid, SES, etc.)
 * when ready for production.
 *
 * The interface is real and must be respected by any replacement implementation.
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the email adapter.
 */
export interface EmailAdapterConfig {
  /** Sender email address (e.g., "noreply@taskflow.com"). */
  fromAddress: string;
  /** Optional: email provider API key. */
  apiKey?: string;
  /** Optional: email provider endpoint. */
  endpoint?: string;
}

/** Default configuration for the email adapter. */
export const defaultEmailConfig: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflow.com',
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: Array<{ payload: NotificationPayload; timestamp: Date }> = [];

  constructor(private config: EmailAdapterConfig = defaultEmailConfig) {}

  /**
   * Send an email notification.
   *
   * Stub implementation: logs the email and records it in-memory.
   * Replace with real email provider integration for production.
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: "${payload.subject}"`,
    );

    // Stub: record the email in-memory instead of actually sending
    this.sentEmails.push({
      payload,
      timestamp: new Date(),
    });

    this.logger.info(
      `Email delivered (stub): ${payload.id} from ${this.config.fromAddress} to ${payload.recipient}`,
    );

    return {
      success: true,
      providerMetadata: {
        from: this.config.fromAddress,
        messageId: `msg-${payload.id}`,
      },
    };
  }

  /**
   * Get all emails sent through this adapter (for testing).
   */
  getSentEmails(): Array<{ payload: NotificationPayload; timestamp: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email records (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

