@@ -0,0 +1,78 @@
+/**
+ * Notification model — core types for the notification system.
+ *
+ * Architecture: All notifications flow through the EventBus. Services emit
+ * domain events (e.g., 'order:created'), the NotificationService listens
+ * and dispatches to the appropriate NotificationAdapter(s) based on channel.
+ *
+ * Constraints:
+ * - All adapters must implement the NotificationAdapter interface.
+ * - All notifications must originate from EventBus event handlers.
+ * - NotificationType must be extended when adding new notification categories.
+ */
+
+/** Supported notification delivery channels. */
+export type NotificationChannel = 'email' | 'webhook' | 'in-app' | 'sms';
+
+/** Categories of notifications the system can send. */
+export type NotificationType =
+  | 'order_confirmation'
+  | 'order_status_update'
+  | 'user_welcome'
+  | 'user_updated';
+
+/** Priority levels for notification delivery. */
+export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';
+
+/**
+ * The payload passed to notification adapters for delivery.
+ * This is the channel-agnostic representation of a notification.
+ */
+export interface NotificationPayload {
+  /** Unique notification ID. */
+  id: string;
+  /** The type/category of this notification. */
+  type: NotificationType;
+  /** Delivery channel for this notification. */
+  channel: NotificationChannel;
+  /** Recipient identifier (email address, user ID, webhook URL, etc.). */
+  recipient: string;
+  /** Notification subject/title. */
+  subject: string;
+  /** Notification body content. */
+  body: string;
+  /** Priority level. */
+  priority: NotificationPriority;
+  /** Additional metadata (order ID, user ID, etc.). */
+  metadata: Record<string, string>;
+  /** When this notification was created. */
+  createdAt: Date;
+}
+
+/**
+ * A persisted notification record with delivery status tracking.
+ */
+export interface Notification extends NotificationPayload {
+  /** Current delivery status. */
+  status: NotificationStatus;
+  /** When delivery was attempted. */
+  sentAt: Date | null;
+  /** Error message if delivery failed. */
+  error: string | null;
+}
+
+/** Delivery status of a notification. */
+export type NotificationStatus = 'pending' | 'sent' | 'failed';
+
+/**
+ * Input for creating a notification (before ID and timestamps are assigned).
+ */
+export interface CreateNotificationInput {
+  type: NotificationType;
+  channel: NotificationChannel;
+  recipient: string;
+  subject: string;
+  body: string;
+  priority?: NotificationPriority;
+  metadata?: Record<string, string>;
+}

